     * academic information (course, level, year) with a newly registered student.
     *
     * @param user the User object containing student details (userId, course, level, year)
     * @throws SQLException if a database error occurs
     */
    public void insertStudentDetails(User user) throws SQLException {
        String sql = "INSERT INTO student_details (user_id, course, level, year) VALUES (?, ?, ?, ?)";
        try (Connection conn = DBConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setInt(1,    user.getUserId());
            ps.setString(2, user.getCourse());
            ps.setString(3, user.getLevel());
            ps.setInt(4,    user.getYear());
            ps.executeUpdate();
        }
    }

    /**
     * Retrieves a user by their email address.
     *
     * Performs a SELECT query with a LEFT JOIN to the `student_details` table.
     * This is commonly used during user login to validate credentials.
     *
     * @param email the email address to search for
     * @return a User object if found (with student details populated if applicable),
     *         or null if no user with that email exists
     * @throws SQLException if a database error occurs
     */
    public User findByEmail(String email) throws SQLException {
        String sql = "SELECT u.*, sd.course, sd.level, sd.year " +
                "FROM users u " +
                "LEFT JOIN student_details sd ON u.user_id = sd.user_id " +
                "WHERE u.email = ?";
        try (Connection conn = DBConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setString(1, email);
            ResultSet rs = ps.executeQuery();
            if (rs.next()) return mapRow(rs);
        }
        return null;
    }

    /**
     * Checks if a user with the given email already exists in the system.
     *
     * Used for validation during registration to ensure email uniqueness.
     *
     * @param email the email address to check
     * @return true if the email already exists, false otherwise
     * @throws SQLException if a database error occurs
     */
    public boolean emailExists(String email) throws SQLException {
        String sql = "SELECT 1 FROM users WHERE email = ?";
        try (Connection conn = DBConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setString(1, email);
            return ps.executeQuery().next();
        }
    }

    /**
     * Checks if a user with the given phone number already exists in the system.
     *
     * Used for validation during registration to ensure phone number uniqueness.
     *
     * @param phone the phone number to check
     * @return true if the phone number already exists, false otherwise
     * @throws SQLException if a database error occurs
     */
    public boolean phoneExists(String phone) throws SQLException {
        String sql = "SELECT 1 FROM users WHERE phone = ?";
        try (Connection conn = DBConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setString(1, phone);
            return ps.executeQuery().next();
        }
    }

    /**
     * Retrieves a user by their unique user ID.
     *
     * Performs a SELECT query with a LEFT JOIN to the `student_details` table
     * to retrieve complete user information including student-specific fields if applicable.
     *
     * @param userId the user ID to search for
     * @return a User object if found (with student details populated if applicable),
     *         or null if no user with that ID exists
     * @throws SQLException if a database error occurs
     */
    public User getUserById(int userId) throws SQLException {
        String sql = "SELECT u.*, sd.course, sd.level, sd.year " +
                "FROM users u " +
                "LEFT JOIN student_details sd ON u.user_id = sd.user_id " +
                "WHERE u.user_id = ?";
        try (Connection conn = DBConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setInt(1, userId);
            ResultSet rs = ps.executeQuery();
            if (rs.next()) return mapRow(rs);
        }
        return null;
    }

    /**
     * Retrieves all students from the system.
     *
     * Used by administrators to view all registered student accounts.
     * Results are ordered by creation date (newest first) and include student-specific details.
     *
     * @return a List of all User objects with role="student", or an empty list if none exist
     * @throws SQLException if a database error occurs
     */
    public List<User> getAllStudents() throws SQLException {
        List<User> list = new ArrayList<>();
        String sql = "SELECT u.*, sd.course, sd.level, sd.year " +
                "FROM users u " +
                "LEFT JOIN student_details sd ON u.user_id = sd.user_id " +
                "WHERE u.role = 'student' ORDER BY u.created_at DESC";
        try (Connection conn = DBConnection.getConnection();
             Statement st = conn.createStatement();
             ResultSet rs = st.executeQuery(sql)) {
            while (rs.next()) list.add(mapRow(rs));
        }
        return list;
    }

    /**
     * Retrieves all students awaiting admin approval.
     *
     * Used by administrators to view new student registrations that require approval.
     * Results are ordered by creation date (oldest first).
     *
     * @return a List of User objects with role="student" and is_approved=0,
     *         or an empty list if none exist
     * @throws SQLException if a database error occurs
     */
    public List<User> getPendingStudents() throws SQLException {
        List<User> list = new ArrayList<>();
        String sql = "SELECT u.*, sd.course, sd.level, sd.year " +
                "FROM users u " +
                "LEFT JOIN student_details sd ON u.user_id = sd.user_id " +
                "WHERE u.role = 'student' AND u.is_approved = 0 ORDER BY u.created_at DESC";
        try (Connection conn = DBConnection.getConnection();
             Statement st = conn.createStatement();
             ResultSet rs = st.executeQuery(sql)) {
            while (rs.next()) list.add(mapRow(rs));
        }
        return list;
    }

    /**
     * Approves a student user account.
     *
     * Sets the is_approved flag to 1, allowing the student to access the system.
     * Used when an administrator approves a pending student registration.
     *
     * @param userId the ID of the student to approve
     * @return true if the update was successful, false otherwise
     * @throws SQLException if a database error occurs
     */
    public boolean approveUser(int userId) throws SQLException {
        String sql = "UPDATE users SET is_approved = 1 WHERE user_id = ?";
        try (Connection conn = DBConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setInt(1, userId);
            return ps.executeUpdate() > 0;
        }
    }

    /**
     * Deletes a user account from the system.
     *
     * Removes the user record from the `users` table. Note that this may cascade
     * to related tables depending on database constraints.
     *
     * @param userId the ID of the user to delete
     * @return true if the deletion was successful, false otherwise
     * @throws SQLException if a database error occurs
     */
    public boolean deleteUser(int userId) throws SQLException {
        String sql = "DELETE FROM users WHERE user_id = ?";
        try (Connection conn = DBConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setInt(1, userId);
            return ps.executeUpdate() > 0;
        }
    }

    /**
     * Updates a user's profile information.
     *
     * Updates the user's full name, phone number, and date of birth.
     * The userId in the User object identifies which record to update.
     *
     * @param user the User object containing the updated profile information
     *             (userId, fullName, phone, dateOfBirth)
     * @return true if the update was successful, false otherwise
     * @throws SQLException if a database error occurs
     */
    public boolean updateProfile(User user) throws SQLException {
        String sql = "UPDATE users SET full_name=?, phone=?, date_of_birth=? WHERE user_id=?";
        try (Connection conn = DBConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setString(1, user.getFullName());
            ps.setString(2, user.getPhone());
            ps.setDate(3,   user.getDateOfBirth());
            ps.setInt(4,    user.getUserId());
            return ps.executeUpdate() > 0;
        }
    }

    /**
     * Updates a user's password.
     * 
     * Sets a new hashed password for the user. This method expects the password
     * to already be hashed by the application (e.g., using {@link util.PasswordUtil}).
     * 
     * @param userId the ID of the user whose password will be updated
     * @param newHashedPassword the new hashed password value
     * @return true if the update was successful, false otherwise
     * @throws SQLException if a database error occurs
     */
    public boolean updatePassword(int userId, String newHashedPassword) throws SQLException {
        String sql = "UPDATE users SET password=? WHERE user_id=?";
        try (Connection conn = DBConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setString(1, newHashedPassword);
            ps.setInt(2,    userId);
            return ps.executeUpdate() > 0;
        }
    }

